export class PluginRegistry {
  private plugins = new Map<string, Plugin>();
  private hooks: PluginHooks = {
    beforeTool: [],
    afterTool: [],
    onError: [],
    onSessionStart: [],
    onSessionEnd: []
  };

  register(plugin: Plugin) {
    if (this.plugins.has(plugin.id)) {
      throw new PluginAlreadyRegisteredError(plugin.id);
    }
    this.plugins.set(plugin.id, plugin);
    this.registerHooks(plugin);
  }

  private registerHooks(plugin: Plugin) {
    if (plugin.hooks) {
      Object.entries(plugin.hooks).forEach(([hookName, handler]) => {
        if (Array.isArray(this.hooks[hookName as keyof PluginHooks])) {
          this.hooks[hookName as keyof PluginHooks].push(handler);
        }
      });
    }
  }

  async executeHook<H extends keyof PluginHooks>(
    hookName: H,
    data: PluginHookData<H>
  ): Promise<void> {
    const handlers = this.hooks[hookName];
    for (const handler of handlers) {
      await handler(data);
    }
  }
}

