export class SkillLoader {
  async loadFromPath(path: string): Promise<SkillDefinition> {
    const skillFile = path join(path, 'SKILL.md');
    const exists = await fs.pathExists(skillFile);
    if (!exists) {
      throw new SkillNotFoundError(path);
    }
    const content = await fs.readFile(skillFile, 'utf-8');
    return this.parseSkillDefinition(content, path);
  }

  private parseSkillDefinition(content: string, location: string): SkillDefinition {
    const parsed = matter(content);
    return {
      name: parsed.data.name,
      description: parsed.data.description,
      location,
      triggers: parsed.data.triggers || [],
      actions: this.extractActions(parsed.content),
      schema: parsed.data.schema
    };
  }
}

