export interface ExecutionPlan {
  steps: ExecutionStep[];
  parallelGroups: number[][];
  estimatedDuration: number;
}

export interface ExecutionStep {
  id: string;
  tool: string;
  args: unknown;
  dependencies: string[];
  parallelWith: string[];
}

export class ExecutionPlanner {
  createPlan(requests: ToolRequest[]): ExecutionPlan {
    const steps = this.buildSteps(requests);
    const parallelGroups = this.identifyParallelGroups(steps);
    const estimatedDuration = this.estimateDuration(parallelGroups, steps);
    return { steps, parallelGroups, estimatedDuration };
  }

  private buildSteps(requests: ToolRequest[]): ExecutionStep[] {
    return requests.map((req, index) => ({
      id: `step_${index}`,
      tool: req.tool,
      args: req.args,
      dependencies: this.findDependencies(req, requests),
      parallelWith: []
    }));
  }

  private findDependencies(request: ToolRequest, allRequests: ToolRequest[]): string[] {
    const deps: string[] = [];
    if (request.after) {
      const afterIndex = allRequests.findIndex(r => r.id === request.after);
      if (afterIndex >= 0) deps.push(`step_${afterIndex}`);
    }
    return deps;
  }

  private identifyParallelGroups(steps: ExecutionStep[]): number[][] {
    const groups: number[][] = [];
    const assigned = new Set<number>();

    steps.forEach((step, index) => {
      if (assigned.has(index)) return;

      const group = steps
        .map((s, i) => ({ step: s, index: i }))
        .filter(({ step, index: i }) => 
          !assigned.has(i) && 
          step.dependencies.every(dep => 
            steps.find(s => s.id === dep)?.dependencies.length === 0 ||
            assigned.has(steps.findIndex(s => s.id === dep))
          )
        )
        .map(({ index }) => index);

      group.forEach(i => assigned.add(i));
      groups.push(group);
    });

    return groups;
  }
}

