export class GatewayCLI {
  constructor(private gateway: Gateway) {}

  async handleCommand(input: string): Promise<string> {
    const { command, args } = this.parseInput(input);

    switch (command) {
      case 'status':
        return this.showStatus();
      case 'start':
        return this.startService(args[0]);
      case 'stop':
        return this.stopService(args[0]);
      case 'restart':
        return this.restartService(args[0]);
      case 'list':
        return this.listServices();
      case 'logs':
        return this.tailLogs(args[0], args[1]);
      default:
        throw new UnknownCommandError(command);
    }
  }

  private parseInput(input: string): { command: string; args: string[] } {
    const parts = input.trim().split(/\s+/);
    return { command: parts[0] || '', args: parts.slice(1) };
  }

  private async showStatus(): Promise<string> {
    const services = await this.gateway.listServices();
    const statusLines = services.map(s => 
      `${s.name}: ${s.status} (pid: ${s.pid || 'N/A'})`
    );
    return statusLines.join('\n');
  }
}

