export interface MemoryStore {
  get(key: string): Promise<unknown>;
  set(key: string, value: unknown, options?: SetOptions): Promise<void>;
  delete(key: string): Promise<void>;
  exists(key: string): Promise<boolean>;
  list(pattern: string): Promise<string[]>;
}

export class RedisMemoryStore implements MemoryStore {
  constructor(private client: Redis) {}

  async get(key: string): Promise<unknown> {
    const data = await this.client.get(key);
    if (!data) return null;
    return JSON.parse(data);
  }

  async set(key: string, value: unknown, options?: SetOptions): Promise<void> {
    const serialized = JSON.stringify(value);
    if (options?.ttl) {
      await this.client.set(key, serialized, { EX: options.ttl });
    } else {
      await this.client.set(key, serialized);
    }
  }

  async delete(key: string): Promise<void> {
    await this.client.del(key);
  }

  async exists(key: string): Promise<boolean> {
    const result = await this.client.exists(key);
    return result === 1;
  }

  async list(pattern: string): Promise<string[]> {
    return await this.client.keys(pattern);
  }
}

