export type ToolHandler = (
  args: unknown,
  context: ToolContext
) => Promise<ToolResult>;

export class ToolPluginManager {
  private plugins = new Map<string, ToolPlugin>();
  private toolHandlers = new Map<string, ToolHandler>();

  registerPlugin(plugin: ToolPlugin): void {
    if (this.plugins.has(plugin.id)) {
      throw new Error(`Plugin ${plugin.id} already registered`);
    }
    this.validatePlugin(plugin);
    this.plugins.set(plugin.id, plugin);
    this.registerTools(plugin);
  }

  private validatePlugin(plugin: ToolPlugin): void {
    if (!plugin.id || !plugin.name) {
      throw new InvalidPluginError('Plugin must have id and name');
    }
    if (!Array.isArray(plugin.tools) || plugin.tools.length === 0) {
      throw new InvalidPluginError('Plugin must define at least one tool');
    }
  }

  private registerTools(plugin: ToolPlugin): void {
    for (const tool of plugin.tools) {
      if (this.toolHandlers.has(tool.name)) {
        throw new ToolAlreadyExistsError(tool.name);
      }
      this.toolHandlers.set(tool.name, tool.handler);
    }
  }

  async executeTool(toolName: string, args: unknown, context: ToolContext): Promise<ToolResult> {
    const handler = this.toolHandlers.get(toolName);
    if (!handler) {
      throw new ToolNotFoundError(toolName);
    }
    return await handler(args, context);
  }
}

