export interface CLICommand {
  name: string;
  description: string;
  options: CommandOption[];
  handler: CommandHandler;
}

export interface CommandOption {
  name: string;
  short?: string;
  type: 'string' | 'number' | 'boolean';
  description: string;
  required?: boolean;
  default?: unknown;
}

export type CommandHandler = (
  args: ParsedArgs,
  context: CLIContext
) => Promise<CLIOutput>;

export class CommandRegistry {
  private commands = new Map<string, CLICommand>();

  register(command: CLICommand): void {
    if (this.commands.has(command.name)) {
      throw new DuplicateCommandError(command.name);
    }
    this.commands.set(command.name, command);
  }

  async execute(input: string, context: CLIContext): Promise<CLIOutput> {
    const parsed = this.parseCommand(input);
    const command = this.commands.get(parsed.name);

    if (!command) {
      throw new CommandNotFoundError(parsed.name);
    }

    const args = this.validateArgs(parsed.args, command.options);
    return await command.handler(args, context);
  }

  private parseCommand(input: string): { name: string; args: string[] } {
    const match = input.match(/^(\w+)(?:\s+(.*))?$/s);
    if (!match) {
      throw new InvalidCommandFormatError();
    }
    return { name: match[1], args: match[2]?.split(/\s+/) || [] };
  }

  private validateArgs(args: string[], options: CommandOption[]): ParsedArgs {
    const parsed: ParsedArgs = {};
    for (const option of options) {
      parsed[option.name] = option.default;
    }
    let i = 0;
    while (i < args.length) {
      const arg = args[i];
      if (arg.startsWith('--')) {
        const optName = arg.slice(2);
        const option = options.find(o => o.name === optName);
        if (!option) throw new UnknownOptionError(optName);
        if (option.type === 'boolean') {
          parsed[option.name] = true;
        } else {
          parsed[option.name] = args[++i];
        }
      }
      i++;
    }
    return parsed;
  }
}

