export class SessionManager {
  private sessions = new Map<string, Session>();
  private sessionTimeout = 30 * 60 * 1000; // 30 minutes

  constructor(
    private storage: SessionStorage,
    private eventBus: EventBus
  ) {}

  async createSession(metadata: SessionMetadata): Promise<Session> {
    const session: Session = {
      id: generateSessionId(),
      createdAt: new Date(),
      lastActivity: new Date(),
      metadata,
      context: {},
      state: 'active'
    };

    await this.storage.save(session);
    this.sessions.set(session.id, session);
    this.eventBus.emit('session:created', session);

    return session;
  }

  async getSession(sessionId: string): Promise<Session | null> {
    let session = this.sessions.get(sessionId);

    if (!session) {
      session = await this.storage.load(sessionId);
      if (session) {
        this.sessions.set(sessionId, session);
      }
    }

    if (session) {
      session.lastActivity = new Date();
    }

    return session || null;
  }

  async updateSession(sessionId: string, updates: Partial<Session>): Promise<void> {
    const session = await this.getSession(sessionId);
    if (!session) {
      throw new SessionNotFoundError(sessionId);
    }

    Object.assign(session, updates);
    session.lastActivity = new Date();
    await this.storage.save(session);
    this.eventBus.emit('session:updated', session);
  }

  async destroySession(sessionId: string): Promise<void> {
    const session = this.sessions.get(sessionId);
    if (session) {
      session.state = 'destroyed';
      this.sessions.delete(sessionId);
      await this.storage.delete(sessionId);
      this.eventBus.emit('session:destroyed', session);
    }
  }

  startCleanupTimer(): void {
    setInterval(() => this.cleanupStaleSessions(), this.sessionTimeout / 2);
  }

  private async cleanupStaleSessions(): Promise<void> {
    const now = Date.now();
    for (const [id, session] of this.sessions) {
      if (now - session.lastActivity.getTime() > this.sessionTimeout) {
        await this.destroySession(id);
      }
    }
  }
}

