export interface PipelineStep<TInput = unknown, TOutput = unknown> {
  name: string;
  execute(input: TInput, context: PipelineContext): Promise<TOutput>;
  rollback?(output: TOutput, context: PipelineContext): Promise<void>;
}

export class ExecutionPipeline {
  private steps: PipelineStep[] = [];
  private results: unknown[] = [];

  addStep<TInput, TOutput>(step: PipelineStep<TInput, TOutput>): this {
    this.steps.push(step as PipelineStep);
    return this;
  }

  async execute(initialInput: unknown): Promise<PipelineResult> {
    const context = this.createContext();
    let currentInput = initialInput;
    const executedSteps: string[] = [];
    const errors: PipelineError[] = [];

    for (const step of this.steps) {
      try {
        const output = await step.execute(currentInput, context);
        this.results.push(output);
        executedSteps.push(step.name);
        currentInput = output;
      } catch (error) {
        const pipelineError: PipelineError = {
          step: step.name,
          message: error.message,
          stack: error.stack
        };
        errors.push(pipelineError);
        await this.rollback(executedSteps, context);
        return { success: false, executedSteps, errors, results: this.results };
      }
    }

    return { success: true, executedSteps, errors: [], results: this.results };
  }

  private createContext(): PipelineContext {
    return {
      pipelineId: generateId(),
      startTime: Date.now(),
      metadata: {}
    };
  }

  private async rollback(executedSteps: string[], context: PipelineContext): Promise<void> {
    const stepsToRollback = this.steps.filter(s => executedSteps.includes(s.name));

    for (const step of stepsToRollback.reverse()) {
      if (step.rollback) {
        try {
          await step.rollback(this.results[this.steps.indexOf(step)], context);
        } catch (rollbackError) {
          console.error(`Rollback failed for step ${step.name}:`, rollbackError);
        }
      }
    }
  }
}

