export interface SkillExecutor {
  execute(skill: Skill, input: unknown, context: ExecutionContext): Promise<SkillResult>;
  validate(skill: Skill): ValidationResult;
}

export class DefaultSkillExecutor implements SkillExecutor {
  constructor(
    private toolRegistry: ToolRegistry,
    private hookRunner: HookRunner
  ) {}

  async execute(skill: Skill, input: unknown, context: ExecutionContext): Promise<SkillResult> {
    const validation = this.validate(skill);
    if (!validation.valid) {
      return { success: false, error: validation.errors.join(', ') };
    }

    await this.hookRunner.run('skill:beforeExecute', { skill, input, context });

    try {
      const action = skill.actions.find(a => a.name === context.requestedAction);
      if (!action) {
        throw new ActionNotFoundError(context.requestedAction);
      }

      const handler = this.resolveHandler(action.handler);
      const result = await handler.execute(input, context);

      await this.hookRunner.run('skill:afterExecute', { skill, result, context });

      return { success: true, result };
    } catch (error) {
      await this.hookRunner.run('skill:onError', { skill, error, context });
      return { success: false, error: error.message };
    }
  }

  validate(skill: Skill): ValidationResult {
    const errors: string[] = [];

    if (!skill.name) errors.push('Skill name is required');
    if (!skill.actions || skill.actions.length === 0) {
      errors.push('Skill must have at least one action');
    }

    for (const action of skill.actions) {
      if (!action.handler) errors.push(`Action ${action.name} must have a handler`);
      if (!action.name) errors.push('Action name is required');
    }

    return { valid: errors.length === 0, errors };
  }

  private resolveHandler(handlerRef: string): Handler {
    // Resolve handler from registry
    return this.toolRegistry.getHandler(handlerRef);
  }
}

