export interface Middleware {
  name: string;
  process(
    request: PluginRequest,
    next: () => Promise<PluginResponse>
  ): Promise<PluginResponse>;
}

export class MiddlewareChain {
  private middlewares: Middleware[] = [];

  use(middleware: Middleware): this {
    this.middlewares.push(middleware);
    return this;
  }

  async execute(request: PluginRequest): Promise<PluginResponse> {
    let index = 0;

    const next = async (): Promise<PluginResponse> => {
      if (index >= this.middlewares.length) {
        throw new Error('No more middleware to execute');
      }

      const middleware = this.middlewares[index++];
      return middleware.process(request, next);
    };

    try {
      return await next();
    } catch (error) {
      return this.handleError(error, request);
    }
  }

  private handleError(error: unknown, request: PluginRequest): PluginResponse {
    const errorMiddleware = this.middlewares.filter(m => 
      m.name.includes('error')
    );

    if (errorMiddleware.length > 0) {
      return errorMiddleware[0].process(request, async () => {
        throw error;
      }) as Promise<PluginResponse>;
    }

    return {
      success: false,
      error: error instanceof Error ? error.message : 'Unknown error',
      requestId: request.id
    };
  }
}

