export interface ToolCallHandler {
  handleToolCall(
    toolName: string,
    args: unknown,
    options?: CallOptions
  ): Promise<CallResult>;
  handleToolBatch(calls: ToolCall[]): Promise<CallResult[]>;
}

export interface CallOptions {
  timeout?: number;
  retries?: number;
  signal?: AbortSignal;
  metadata?: Record<string, unknown>;
}

export class DefaultToolCallHandler implements ToolCallHandler {
  constructor(
    private registry: ToolRegistry,
    private executor: ToolExecutor
  ) {}

  async handleToolCall(
    toolName: string,
    args: unknown,
    options: CallOptions = {}
  ): Promise<CallResult> {
    const tool = this.registry.getTool(toolName);
    if (!tool) {
      return { success: false, error: `Tool not found: ${toolName}` };
    }

    const startTime = Date.now();
    let attempts = 0;
    const maxRetries = options.retries || 0;

    while (attempts <= maxRetries) {
      try {
        const result = await this.executeWithTimeout(
          tool,
          args,
          options.timeout || 30000
        );

        return {
          success: true,
          result,
          duration: Date.now() - startTime,
          toolName
        };
      } catch (error) {
        attempts++;
        if (attempts > maxRetries) {
          return {
            success: false,
            error: error.message,
            duration: Date.now() - startTime,
            toolName,
            attempts
          };
        }
        await this.delay(Math.pow(2, attempts) * 100);
      }
    }

    return { success: false, error: 'Max retries exceeded', toolName };
  }

  private async executeWithTimeout(
    tool: Tool,
    args: unknown,
    timeout: number
  ): Promise<unknown> {
    return Promise.race([
      this.executor.execute(tool, args),
      new Promise((_, reject) =>
        setTimeout(() => reject(new Error('Tool call timeout')), timeout)
      )
    ]);
  }

  private delay(ms: number): Promise<void> {
    return new Promise(resolve => setTimeout(resolve, ms));
  }

  async handleToolBatch(calls: ToolCall[]): Promise<CallResult[]> {
    const results = await Promise.all(
      calls.map(call => this.handleToolCall(call.tool, call.args, call.options))
    );
    return results;
  }
}

