export interface MemoryIndex {
  add(key: string, value: unknown): void;
  remove(key: string): void;
  search(query: string, limit?: number): string[];
  rebuild(): void;
}

export class InMemoryIndex implements MemoryIndex {
  private index: Map<string, Set<string>> = new Map();
  private documents: Map<string, unknown> = new Map();
  private tokenizer: Tokenizer;

  constructor(tokenizer?: Tokenizer) {
    this.tokenizer = tokenizer || new DefaultTokenizer();
  }

  add(key: string, value: unknown): void {
    this.documents.set(key, value);
    const tokens = this.tokenizer.tokenize(JSON.stringify(value));

    for (const token of tokens) {
      if (!this.index.has(token)) {
        this.index.set(token, new Set());
      }
      this.index.get(token)!.add(key);
    }
  }

  remove(key: string): void {
    const value = this.documents.get(key);
    if (value) {
      const tokens = this.tokenizer.tokenize(JSON.stringify(value));
      for (const token of tokens) {
        this.index.get(token)?.delete(key);
      }
      this.documents.delete(key);
    }
  }

  search(query: string, limit = 10): string[] {
    const queryTokens = this.tokenizer.tokenize(query);
    const scores = new Map<string, number>();

    for (const token of queryTokens) {
      const keys = this.index.get(token);
      if (keys) {
        for (const key of keys) {
          scores.set(key, (scores.get(key) || 0) + 1);
        }
      }
    }

    return Array.from(scores.entries())
      .sort((a, b) => b[1] - a[1])
      .slice(0, limit)
      .map(([key]) => key);
  }

  rebuild(): void {
    const keys = Array.from(this.documents.keys());
    this.index.clear();
    for (const key of keys) {
      const value = this.documents.get(key);
      const tokens = this.tokenizer.tokenize(JSON.stringify(value));
      for (const token of tokens) {
        if (!this.index.has(token)) {
          this.index.set(token, new Set());
        }
        this.index.get(token)!.add(key);
      }
    }
  }
}

