export interface ToolDependency {
  type: 'required' | 'optional' | 'conflicting';
  tool: string;
  condition?: (context: Context) => boolean;
}

export interface ToolSpec {
  name: string;
  dependencies?: ToolDependency[];
  provides?: string[];
  consumes?: string[];
}

export class DependencyResolver {
  private toolSpecs = new Map<string, ToolSpec>();

  registerSpec(spec: ToolSpec): void {
    this.toolSpecs.set(spec.name, spec);
  }

  resolve(tools: string[], context: Context): ResolutionResult {
    const resolved: string[] = [];
    const missing: string[] = [];
    const conflicts: Conflict[] = [];
    const resolvedSet = new Set<string>();

    for (const tool of tools) {
      const result = this.resolveTool(tool, context, resolvedSet);
      if (result.success) {
        resolved.push(tool);
        resolvedSet.add(tool);
        result.addedTools?.forEach(t => {
          if (!resolvedSet.has(t)) {
            resolved.push(t);
            resolvedSet.add(t);
          }
        });
      } else {
        missing.push(tool);
      }
      if (result.conflicts) {
        conflicts.push(...result.conflicts);
      }
    }

    return { resolved, missing, conflicts, success: missing.length === 0 };
  }

  private resolveTool(
    tool: string,
    context: Context,
    resolved: Set<string>
  ): ToolResolutionResult {
    const spec = this.toolSpecs.get(tool);
    if (!spec) {
      return { success: true };
    }

    const addedTools: string[] = [];
    const conflicts: Conflict[] = [];

    if (spec.dependencies) {
      for (const dep of spec.dependencies) {
        if (dep.type === 'required') {
          if (!resolved.has(dep.tool)) {
            const depSpec = this.toolSpecs.get(dep.tool);
            if (depSpec) {
              addedTools.push(dep.tool);
            }
          }
        } else if (dep.type === 'conflicting') {
          if (resolved.has(dep.tool)) {
            conflicts.push({ tool, conflictingTool: dep.tool });
          }
        }
      }
    }

    return { success: conflicts.length === 0, addedTools, conflicts };
  }
}

