export class PatternTriggerEvaluator implements SkillTriggerEvaluator {
  constructor(private patternCache: PatternCache) {}

  async evaluate(trigger: SkillTrigger, context: TriggerContext): Promise<boolean> {
    if (trigger.type !== 'pattern') {
      return false;
    }

    const { pattern, flags } = trigger.config as PatternConfig;
    let regex = this.patternCache.get(pattern);

    if (!regex) {
      regex = new RegExp(pattern, flags || 'i');
      this.patternCache.set(pattern, regex);
    }

    const input = this.getInputText(context);
    return regex.test(input);
  }

  private getInputText(context: TriggerContext): string {
    if (typeof context.input === 'string') {
      return context.input;
    }
    return JSON.stringify(context.input);
  }
}

export class IntentTriggerEvaluator implements SkillTriggerEvaluator {
  private intentClassifier: IntentClassifier;

  constructor(classifier: IntentClassifier) {
    this.intentClassifier = classifier;
  }

  async evaluate(trigger: SkillTrigger, context: TriggerContext): Promise<boolean> {
    if (trigger.type !== 'intent') {
      return false;
    }

    const { intent, threshold = 0.7 } = trigger.config as IntentConfig;
    const classification = await this.intentClassifier.classify(context.input);

    return (
      classification.intent === intent &&
      classification.confidence >= threshold
    );
  }
}

export class ScheduleTriggerEvaluator implements SkillTriggerEvaluator {
  evaluate(trigger: SkillTrigger, context: TriggerContext): boolean {
    if (trigger.type !== 'schedule') {
      return false;
    }

    const { cron, interval } = trigger.config as ScheduleConfig;

    if (cron) {
      return this.matchesCron(cron, context.timestamp);
    }

    if (interval) {
      return this.matchesInterval(interval, context.timestamp);
    }

    return false;
  }

  private matchesCron(cron: string, timestamp: Date): boolean {
    const parts = cron.split(' ');
