export interface InteractiveCLI extends EventEmitter {
  prompt(question: string, options?: PromptOptions): Promise<string>;
  confirm(question: string, defaultValue?: boolean): Promise<boolean>;
  select<T>(question: string, options: SelectOption<T>[]): Promise<T>;
  multiline(prompt: string): Promise<string>;
  password(prompt: string): Promise<string>;
}

export class TerminalCLI implements InteractiveCLI {
  private input: ReadlineInterface;
  private output: WritableStream;

  constructor(input: ReadlineInterface, output: WritableStream) {
    this.input = input;
    this.output = output;
  }

  async prompt(question: string, options: PromptOptions = {}): Promise<string> {
    const defaultValue = options.default || '';
    const suffix = defaultValue ? ` [${defaultValue}]` : '';

    return new Promise((resolve) => {
      this.input.question(`${question}${suffix}: `, (answer) => {
        resolve(answer || defaultValue);
      });
    });
  }

  async confirm(question: string, defaultValue = true): Promise<boolean> {
    const suffix = defaultValue ? '[Y/n]' : '[y/N]';
    const answer = await this.prompt(`${question} ${suffix}`);

    if (!answer) return defaultValue;
    return /^[Yy]/.test(answer);
  }

  async select<T>(question: string, options: SelectOption<T>[]): Promise<T> {
    this.output.write(`${question}:\n`);

    options.forEach((opt, index) => {
      this.output.write(`  ${index + 1}. ${opt.label}\n`);
    });

    const answer = await this.prompt('Enter number');
    const index = parseInt(answer, 10) - 1;

    if (index >= 0 && index < options.length) {
      return options[index].value;
    }

    throw new Error('Invalid selection');
  }

  async multiline(prompt: string): Promise<string> {
    this.output.write(`${prompt} (press Ctrl+D to finish):\n`);

    const lines: string[] = [];

    return new Promise((resolve) => {
      this.input.on('line', (line) => {
        lines.push(line);
      });

      this.input.on('close', () => {
        resolve(lines.join('\n'));
      });
    });
  }

  async password(prompt: string): Promise<string> {
    return new Promise((resolve) => {
      this.input.question(prompt, (answer) => {
        resolve(answer);
      });
    });
  }
}

