export interface RateLimiter {
  acquire(key: string, tokens?: number): Promise<boolean>;
  waitFor(key: string, tokens?: number): Promise<void>;
  reset(key: string): void;
  getStatus(key: string): RateLimitStatus;
}

export interface RateLimitStatus {
  remaining: number;
  resetAt: Date;
  retryAfter?: number;
}

export class TokenBucketRateLimiter implements RateLimiter {
  private buckets = new Map<string, TokenBucket>();

  constructor(
    private capacity: number,
    private refillRate: number,
    private clock: Clock = Date
  ) {}

  async acquire(key: string, tokens = 1): Promise<boolean> {
    const bucket = this.getBucket(key);
    return bucket.consume(tokens);
  }

  async waitFor(key: string, tokens = 1): Promise<void> {
    while (!(await this.acquire(key, tokens))) {
      const bucket = this.getBucket(key);
      await this.delay(bucket.getWaitTime(tokens));
    }
  }

  reset(key: string): void {
    this.buckets.delete(key);
  }

  getStatus(key: string): RateLimitStatus {
    const bucket = this.getBucket(key);
    return {
      remaining: bucket.available,
      resetAt: new Date(bucket.refillAt),
      retryAfter: bucket.getWaitTime(1)
    };
  }

  private getBucket(key: string): TokenBucket {
    let bucket = this.buckets.get(key);
    if (!bucket) {
      bucket = new TokenBucket(this.capacity, this.refillRate, this.clock);
      this.buckets.set(key, bucket);
    }
    return bucket;
  }

  private delay(ms: number): Promise<void> {
    return new Promise(resolve => setTimeout(resolve, ms));
  }
}

class TokenBucket {
  available: number;
  refillAt: number;

  constructor(
    private capacity: number,
    private refillRate: number,
    private clock: Clock
  ) {
    this.available = capacity;
    this.refillAt = clock.now();
  }

  consume(tokens: number): boolean {
    this.refill();
    if (this.available >= tokens) {
      this.available -= tokens;
      return true;
    }
    return false;
  }

  private refill(): void {
    const now = this.clock.now();
    const elapsed = (now - this.refillAt) / 1000;
    const tokensToAdd = elapsed * this.refillRate;
    this.available = Math.min(this.capacity, this.available + tokensToAdd);
    this.refillAt = now;
  }

  getWaitTime(tokens: number): number {
    if (this.available >= tokens) return 0;
    return Math.ceil((tokens - this.available) / this.refillRate * 1000);
  }
}

