export interface PluginHotReload {
  watch(pluginId: string): void;
  unwatch(pluginId: string): void;
  reload(pluginId: string): Promise<void>;
  getStatus(pluginId: string): ReloadStatus;
}

export interface ReloadStatus {
  watching: boolean;
  lastReload?: Date;
  reloadCount: number;
  errors: string[];
}

export class FileWatcherHotReload implements PluginHotReload {
  private watchers = new Map<string, FSWatcher>();
  private status = new Map<string, ReloadStatus>();
  private debounceTimers = new Map<string, NodeJS.Timeout>();

  constructor(
    private pluginManager: PluginManager,
    private debounceMs = 500
  ) {}

  watch(pluginId: string): void {
    if (this.watchers.has(pluginId)) {
      return;
    }

    const plugin = this.pluginManager.getPlugin(pluginId);
    if (!plugin) {
      throw new PluginNotFoundError(pluginId);
    }

    const pluginPath = plugin.location;
    const watcher = fs.watch(pluginPath, { recursive: true }, (eventType, filename) => {
      this.handleFileChange(pluginId, filename);
    });

    this.watchers.set(pluginId, watcher);
    this.status.set(pluginId, {
      watching: true,
      reloadCount: 0,
      errors: []
    });

    watcher.on('error', (error) => {
      this.handleError(pluginId, error);
    });
  }

  private handleFileChange(pluginId: string, filename: string): void {
    const existingTimer = this.debounceTimers.get(pluginId);
    if (existingTimer) {
      clearTimeout(existingTimer);
    }

    const timer = setTimeout(async () => {
      await this.reload(pluginId);
    }, this.debounceMs);

    this.debounceTimers.set(pluginId, timer);
  }

  async reload(pluginId: string): Promise<void> {
    const status = this.status.get(pluginId);
    if (!status) {
      throw new PluginNotFoundError(pluginId);
    }

    try {
      await this.pluginManager.reloadPlugin(pluginId);
      status.lastReload = new Date();
      status.reloadCount++;
      status.errors = [];
    } catch (error) {
      status.errors.push(error.message);
    }
  }

  unwatch(pluginId: string): void {
    const watcher = this.watchers.get(pluginId);
    if (watcher) {
      watcher.close();
      this.watchers.delete(pluginId);
      this.status.delete(pluginId);
    }
  }

  getStatus(pluginId: string): ReloadStatus {
    return this.status.get(pluginId) || { watching: false, reloadCount: 0, errors: [] };
  }
}

