export interface CommandHistory {
  add(command: string): void;
  getRecent(count: number): string[];
  search(query: string): string[];
  clear(): void;
}

export class PersistentCommandHistory implements CommandHistory {
  private history: string[] = [];
  private historyPath: string;
  private maxSize: number;

  constructor(historyPath: string, maxSize = 1000) {
    this.historyPath = historyPath;
    this.maxSize = maxSize;
    this.load();
  }

  private async load(): Promise<void> {
    try {
      const content = await fs.readFile(this.historyPath, 'utf-8');
      this.history = content.split('\n').filter(line => line.trim());
    } catch {
      this.history = [];
    }
  }

  private async save(): Promise<void> {
    await fs.writeFile(this.historyPath, this.history.join('\n'), 'utf-8');
  }

  add(command: string): void {
    // Avoid duplicate consecutive entries
    if (this.history[0] === command) {
      return;
    }

    this.history.unshift(command);

    if (this.history.length > this.maxSize) {
      this.history = this.history.slice(0, this.maxSize);
    }

    this.save();
  }

  getRecent(count: number): string[] {
    return this.history.slice(0, count);
  }

  search(query: string): string[] {
    const lowerQuery = query.toLowerCase();
    return this.history.filter(cmd => 
      cmd.toLowerCase().includes(lowerQuery)
    );
  }

  clear(): void {
    this.history = [];
    this.save();
  }
}

