export interface ContextWindow {
  addMessage(message: Message): void;
  addMessages(messages: Message[]): void;
  getMessages(limit?: number): Message[];
  getTokenCount(): number;
  truncate(maxTokens: number): void;
  clear(): void;
}

export interface Message {
  role: 'system' | 'user' | 'assistant' | 'tool';
  content: string;
  name?: string;
  toolCallId?: string;
  metadata?: Record<string, unknown>;
}

export class SlidingContextWindow implements ContextWindow {
  private messages: Message[] = [];
  private tokenCounter: TokenCounter;

  constructor(
    private maxTokens: number,
    tokenCounter?: TokenCounter
  ) {
    this.tokenCounter = tokenCounter || new GPT4TokenCounter();
  }

  addMessage(message: Message): void {
    this.messages.push(message);
    this.evictIfNeeded();
  }

  addMessages(messages: Message[]): void {
    for (const message of messages) {
      this.messages.push(message);
    }
    this.evictIfNeeded();
  }

  getMessages(limit?: number): Message[] {
    if (limit) {
      return this.messages.slice(-limit);
    }
    return [...this.messages];
  }

  getTokenCount(): number {
    return this.tokenCounter.count(this.messages);
  }

  truncate(maxTokens: number): void {
    while (this.getTokenCount() > maxTokens && this.messages.length > 1) {
      this.messages.shift();
    }
  }

  clear(): void {
    this.messages = [];
  }

  private evictIfNeeded(): void {
    while (this.getTokenCount() > this.maxTokens && this.messages.length > 1) {
      // Remove oldest non-system message
      const nonSystemIndex = this.messages.findIndex(
        (m, i) => i > 0 && m.role !== 'system'
      );
      if (nonSystemIndex > 0) {
        this.messages.splice(nonSystemIndex, 1);
      } else {
        break;
      }
    }
  }
}

