export interface ToolCache {
  get(key: string): Promise<CachedResult | null>;
  set(key: string, result: unknown, ttl?: number): Promise<void>;
  invalidate(key: string): Promise<void>;
  invalidatePattern(pattern: string): Promise<void>;
  clear(): Promise<void>;
}

export interface CachedResult {
  result: unknown;
  cachedAt: number;
  expiresAt: number;
}

export class LRUToolCache implements ToolCache {
  private cache = new Map<string, CachedResult>();
  private accessOrder: string[] = [];

  constructor(
    private maxSize: number = 1000,
    private defaultTTL: number = 3600000
  ) {}

  async get(key: string): Promise<CachedResult | null> {
    const entry = this.cache.get(key);

    if (!entry) return null;

    if (Date.now() > entry.expiresAt) {
      this.cache.delete(key);
      this.removeFromAccessOrder(key);
      return null;
    }

    this.updateAccessOrder(key);
    return entry;
  }

  async set(key: string, result: unknown, ttl = this.defaultTTL): Promise<void> {
    const now = Date.now();
    const entry: CachedResult = {
      result,
      cachedAt: now,
      expiresAt: now + ttl
    };

    if (this.cache.has(key)) {
      this.cache.set(key, entry);
    } else {
      if (this.cache.size >= this.maxSize) {
        this.evictLRU();
      }
      this.cache.set(key, entry);
    }

    this.updateAccessOrder(key);
  }

  async invalidate(key: string): Promise<void> {
    this.cache.delete(key);
    this.removeFromAccessOrder(key);
  }

  async invalidatePattern(pattern: string): Promise<void> {
    const regex = new RegExp(pattern);
    const keysToDelete: string[] = [];

    for (const key of this.cache.keys()) {
      if (regex.test(key)) {
        keysToDelete.push(key);
      }
    }

    for (const key of keysToDelete) {
      await this.invalidate(key);
    }
  }

  async clear(): Promise<void> {
    this.cache.clear();
    this.accessOrder = [];
  }

  private updateAccessOrder(key: string): void {
    this.removeFromAccessOrder(key);
    this.accessOrder.unshift(key);
  }

  private removeFromAccessOrder(key: string): void {
    const index = this.accessOrder.indexOf(key);
    if (index > -1) {
      this.accessOrder.splice(index, 1);
    }
  }

  private evictLRU(): void {
    const lruKey = this.accessOrder.pop();
    if (lruKey) {
      this.cache.delete(lruKey);
    }
  }
}

