export interface SkillEventBus {
  subscribe(event: SkillEvent, handler: EventHandler): UnsubscribeFn;
  publish(event: SkillEvent, data: unknown): void;
  once(event: SkillEvent, handler: EventHandler): UnsubscribeFn;
}

export type SkillEvent = 
  | 'skill:loaded'
  | 'skill:unloaded'
  | 'skill:error'
  | 'skill:action:start'
  | 'skill:action:complete'
  | 'skill:trigger:matched';

export type EventHandler = (data: unknown) => void | Promise<void>;
export type UnsubscribeFn = () => void;

export class TypedSkillEventBus implements SkillEventBus {
  private handlers = new Map<SkillEvent, Set<EventHandler>>();

  subscribe(event: SkillEvent, handler: EventHandler): UnsubscribeFn {
    if (!this.handlers.has(event)) {
      this.handlers.set(event, new Set());
    }
    this.handlers.get(event)!.add(handler);

    return () => {
      this.handlers.get(event)?.delete(handler);
    };
  }

  once(event: SkillEvent, handler: EventHandler): UnsubscribeFn {
    const wrappedHandler = async (data: unknown) => {
      handler(data);
      this.handlers.get(event)?.delete(wrappedHandler);
    };
    return this.subscribe(event, wrappedHandler);
  }

  publish(event: SkillEvent, data: unknown): void {
    const eventHandlers = this.handlers.get(event);
    if (!eventHandlers) return;

    for (const handler of eventHandlers) {
      try {
        const result = handler(data);
        if (result instanceof Promise) {
          result.catch(error => {
            console.error(`Error in event handler for ${event}:`, error);
          });
        }
      } catch (error) {
        console.error(`Error in event handler for ${event}:`, error);
      }
    }
  }

  getSubscriberCount(event: SkillEvent): number {
    return this.handlers.get(event)?.size || 0;
  }

  clear(event?: SkillEvent): void {
    if (event) {
      this.handlers.delete(event);
    } else {
      this.handlers.clear();
    }
  }
}

