export interface ConfigProperty {
  type: 'string' | 'number' | 'boolean' | 'array' | 'object';
  description?: string;
  default?: unknown;
  enum?: unknown[];
  pattern?: string;
  minimum?: number;
  maximum?: number;
}

export class PluginConfigManager {
  private configs = new Map<string, Record<string, unknown>>();
  private schemas = new Map<string, PluginConfigSchema>();

  registerSchema(pluginId: string, schema: PluginConfigSchema): void {
    this.schemas.set(pluginId, schema);
    if (!this.configs.has(pluginId)) {
      this.configs.set(pluginId, this.getDefaults(schema));
    }
  }

  getConfig<T = Record<string, unknown>>(pluginId: string): T {
    return (this.configs.get(pluginId) || {}) as T;
  }

  async updateConfig(
    pluginId: string,
    updates: Record<string, unknown>
  ): Promise<void> {
    const schema = this.schemas.get(pluginId);
    if (!schema) {
      throw new SchemaNotFoundError(pluginId);
    }

    this.validate(updates, schema);
    const current = this.configs.get(pluginId) || {};
    this.configs.set(pluginId, { ...current, ...updates });
  }

  private validate(data: Record<string, unknown>, schema: PluginConfigSchema): void {
    const errors: string[] = [];

    for (const key of schema.required || []) {
      if (!(key in data)) {
        errors.push(`Required field missing: ${key}`);
      }
    }

    for (const [key, value] of Object.entries(data)) {
      const prop = schema.properties[key];
      if (!prop) {
        errors.push(`Unknown field: ${key}`);
        continue;
      }

      if (!this.validateType(value, prop)) {
        errors.push(`Invalid type for ${key}: expected ${prop.type}`);
      }

      if (prop.enum && !prop.enum.includes(value)) {
        errors.push(`Value for ${key} must be one of: ${prop.enum.join(', ')}`);
      }

      if (prop.pattern && typeof value === 'string') {
        const regex = new RegExp(prop.pattern);
        if (!regex.test(value)) {
          errors.push(`Value for ${key} does not match pattern`);
        }
      }
    }

    if (errors.length > 0) {
      throw new ConfigValidationError(errors.join('; '));
    }
  }

  private validateType(value: unknown, prop: ConfigProperty): boolean {
    switch (prop.type) {
      case 'string': return typeof value === 'string';
      case 'number': return typeof value === 'number';
      case 'boolean': return typeof value === 'boolean';
      case 'array': return Array.isArray(value);
      case 'object': return typeof value === 'object' && value !== null && !Array.isArray(value);
      default: return false;
    }
  }

  private getDefaults(schema: PluginConfigSchema): Record<string, unknown> {
    const defaults: Record<string, unknown> = {};
    for (const [key, prop] of Object.entries(schema.properties)) {
      if ('default' in prop) {
        defaults[key] = prop.default;
      }
    }
    return defaults;
  }
}

