export interface AutoCompleteProvider {
  getCompletions(
    word: string,
    context: AutoCompleteContext
  ): Promise<Completion[]>;
}

export interface Completion {
  label: string;
  kind: 'command' | 'option' | 'argument' | 'file' | 'skill' | 'tool';
  insertText: string;
  detail?: string;
  description?: string;
  priority?: number;
}

export interface AutoCompleteContext {
  cursor: number;
  line: string;
  command?: string;
  position: 'command' | 'option' | 'argument';
  availableCommands?: string[];
  availableOptions?: string[];
}

export class HybridAutoCompleteProvider implements AutoCompleteProvider {
  constructor(
    private commandProvider: CommandAutoCompleteProvider,
    private fileProvider: FileAutoCompleteProvider,
    private skillProvider: SkillAutoCompleteProvider
  ) {}

  async getCompletions(
    word: string,
    context: AutoCompleteContext
  ): Promise<Completion[]> {
    const providers = this.getProviders(context.position);
    const results = await Promise.all(
      providers.map(p => p.getCompletions(word, context))
    );

    return this.mergeAndSort(
      results.flat(),
      word,
      context.priority
    );
  }

  private getProviders(position: string): AutoCompleteProvider[] {
    switch (position) {
      case 'command':
        return [this.commandProvider];
      case 'option':
        return [this.commandProvider];
      case 'argument':
        return [this.fileProvider, this.skillProvider];
      default:
        return [this.commandProvider, this.fileProvider, this.skillProvider];
    }
  }

  private mergeAndSort(
    completions: Completion[],
    word: string,
    priority?: string[]
  ): Completion[] {
    const seen = new Set<string>();
    const unique: Completion[] = [];

    for (const completion of completions) {
      if (!seen.has(completion.insertText)) {
        seen.add(completion.insertText);
        unique.push(completion);
      }
    }

    return unique.sort((a, b) => {
      const aStarts = a.insertText.startsWith(word.toLowerCase());
      const bStarts = b.insertText.startsWith(word.toLowerCase());

      if (aStarts && !bStarts) return -1;
      if (!aStarts && bStarts) return 1;

      return (b.priority || 0) - (a.priority || 0);
    });
  }
}

