export interface MemorySnapshot {
  id: string;
  sessionId: string;
  timestamp: Date;
  messages: Message[];
  metadata: Record<string, unknown>;
  size: number;
}

export class MemorySnapshotManager {
  private snapshots = new Map<string, MemorySnapshot>();
  private storage: SnapshotStorage;

  constructor(storage: SnapshotStorage) {
    this.storage = storage;
  }

  async createSnapshot(sessionId: string, context: SessionContext): Promise<MemorySnapshot> {
    const snapshot: MemorySnapshot = {
      id: generateSnapshotId(),
      sessionId,
      timestamp: new Date(),
      messages: [...context.messages],
      metadata: context.metadata,
      size: this.estimateSize(context.messages)
    };

    await this.storage.save(snapshot);
    this.snapshots.set(snapshot.id, snapshot);

    return snapshot;
  }

  async restoreSnapshot(snapshotId: string): Promise<MemorySnapshot | null> {
    const cached = this.snapshots.get(snapshotId);
    if (cached) return cached;

    const snapshot = await this.storage.load(snapshotId);
    if (snapshot) {
      this.snapshots.set(snapshotId, snapshot);
    }

    return snapshot;
  }

  async listSnapshots(
    sessionId: string,
    options?: { limit?: number; before?: Date }
  ): Promise<MemorySnapshot[]> {
    return this.storage.list(sessionId, options);
  }

  async deleteSnapshot(snapshotId: string): Promise<void> {
    await this.storage.delete(snapshotId);
    this.snapshots.delete(snapshotId);
  }

  async pruneOldSnapshots(sessionId: string, keepCount: number): Promise<void> {
    const snapshots = await this.listSnapshots(sessionId, { limit: keepCount * 2 });
    const sorted = snapshots.sort((a, b) => 
      b.timestamp.getTime() - a.timestamp.getTime()
    );
    const toDelete = sorted.slice(keepCount);

    for (const snapshot of toDelete) {
      await this.deleteSnapshot(snapshot.id);
    }
  }

  private estimateSize(messages: Message[]): number {
    return new TextEncoder().encode(
      JSON.stringify(messages)
    ).length;
  }
}

