export interface RetryPolicy {
  shouldRetry(error: Error, attempt: number): boolean;
  getDelay(attempt: number): number;
  getMaxAttempts(): number;
}

export class ExponentialBackoffRetryPolicy implements RetryPolicy {
  constructor(
    private baseDelay = 1000,
    private maxDelay = 30000,
    private maxAttempts = 3,
    private jitter = true
  ) {}

  shouldRetry(error: Error, attempt: number): boolean {
    if (attempt >= this.maxAttempts) {
      return false;
    }

    // Don't retry on client errors
    if (error.message.includes('400') || error.message.includes('401')) {
      return false;
    }

    return true;
  }

  getDelay(attempt: number): number {
    const delay = Math.min(
      this.baseDelay * Math.pow(2, attempt),
      this.maxDelay
    );

    if (this.jitter) {
      return delay * (0.5 + Math.random() * 0.5);
    }

    return delay;
  }

  getMaxAttempts(): number {
    return this.maxAttempts;
  }
}

export class FixedRetryPolicy implements RetryPolicy {
  constructor(
    private delay: number,
    private maxAttempts = 3
  ) {}

  shouldRetry(error: Error, attempt: number): boolean {
    return attempt < this.maxAttempts;
  }

  getDelay(attempt: number): number {
    return this.delay;
  }

  getMaxAttempts(): number {
    return this.maxAttempts;
  }
}

export class RetryExecutor {
  execute<T>(
    fn: () => Promise<T>,
    policy: RetryPolicy
  ): Promise<T> {
    return this.executeWithRetry(fn, policy, 0);
  }

  private async executeWithRetry<T>(
    fn: () => Promise<T>,
    policy: RetryPolicy,
    attempt: number
  ): Promise<T> {
    try {
      return await fn();
    } catch (error) {
      const shouldRetry = policy.shouldRetry(error as Error, attempt);

      if (!shouldRetry) {
        throw error;
      }

      const delay = policy.getDelay(attempt);
      await this.sleep(delay);

      return this.executeWithRetry(fn, policy, attempt + 1);
    }
  }

  private sleep(ms: number): Promise<void> {
    return new Promise(resolve => setTimeout(resolve, ms));
  }
}

