export interface SkillPermission {
  skill: string;
  actions: string[];
  conditions?: PermissionCondition[];
}

export interface PermissionCondition {
  field: string;
  operator: 'eq' | 'neq' | 'gt' | 'lt' | 'in' | 'contains';
  value: unknown;
}

export class PermissionManager {
  private permissions = new Map<string, SkillPermission[]>();
  private defaultPolicy: 'allow' | 'deny' = 'deny';

  registerPermission(principal: string, permission: SkillPermission): void {
    if (!this.permissions.has(principal)) {
      this.permissions.set(principal, []);
    }
    this.permissions.get(principal)!.push(permission);
  }

  hasPermission(
    principal: string,
    skill: string,
    action: string,
    context?: Record<string, unknown>
  ): boolean {
    const principalPermissions = this.permissions.get(principal);

    if (!principalPermissions) {
      return this.defaultPolicy === 'allow';
    }

    for (const permission of principalPermissions) {
      if (permission.skill === skill && permission.actions.includes(action)) {
        if (!permission.conditions) {
          return true;
        }
        if (this.evaluateConditions(permission.conditions, context || {})) {
          return true;
        }
      }
    }

    return false;
  }

  private evaluateConditions(
    conditions: PermissionCondition[],
    context: Record<string, unknown>
  ): boolean {
    return conditions.every(condition => {
      const value = this.getNestedValue(context, condition.field);
      return this.evaluateCondition(value, condition);
    });
  }

  private getNestedValue(obj: Record<string, unknown>, path: string): unknown {
    return path.split('.').reduce((acc: unknown, key) => {
      if (acc && typeof acc === 'object') {
        return (acc as Record<string, unknown>)[key];
      }
      return undefined;
    }, obj);
  }

  private evaluateCondition(
    value: unknown,
    condition: PermissionCondition
  ): boolean {
    switch (condition.operator) {
      case 'eq': return value === condition.value;
      case 'neq': return value !== condition.value;
      case 'gt': return (value as number) > (condition.value as number);
      case 'lt': return (value as number) < (condition.value as number);
      case 'in': return Array.isArray(condition.value) && condition.value.includes(value);
      case 'contains': return String(value).includes(String(condition.value));
      default: return false;
    }
  }

  revokePermission(principal: string, skill: string, action: string): void {
    const principalPermissions = this.permissions.get(principal);
    if (principalPermissions) {
      const index = principalPermissions.findIndex(
        p => p.skill === skill && p.actions.includes(action)
      );
      if (index > -1) {
        principalPermissions.splice(index, 1);
      }
    }
  }
}

