export interface PluginMetrics {
  pluginId: string;
  invocations: number;
  errors: number;
  avgDuration: number;
  lastInvoked?: Date;
  successRate: number;
}

export class PluginMetricsCollector {
  private metrics = new Map<string, MetricRecord[]>();
  private aggregationInterval = 60000; // 1 minute

  recordInvocation(
    pluginId: string,
    duration: number,
    success: boolean
  ): void {
    if (!this.metrics.has(pluginId)) {
      this.metrics.set(pluginId, []);
    }

    this.metrics.get(pluginId)!.push({
      timestamp: Date.now(),
      duration,
      success
    });

    this.pruneOldMetrics(pluginId);
  }

  getMetrics(pluginId: string, windowMs?: number): PluginMetrics {
    const records = this.getRecordsInWindow(pluginId, windowMs);

    const totalDuration = records.reduce((sum, r) => sum + r.duration, 0);
    const errors = records.filter(r => !r.success).length;

    return {
      pluginId,
      invocations: records.length,
      errors,
      avgDuration: records.length > 0 ? totalDuration / records.length : 0,
      lastInvoked: records.length > 0 
        ? new Date(records[records.length - 1].timestamp) 
        : undefined,
      successRate: records.length > 0 ? (records.length - errors) / records.length : 0
    };
  }

  private getRecordsInWindow(pluginId: string, windowMs?: number): MetricRecord[] {
    const records = this.metrics.get(pluginId) || [];
    if (!windowMs) return records;

    const cutoff = Date.now() - windowMs;
    return records.filter(r => r.timestamp >= cutoff);
  }

  private pruneOldMetrics(pluginId: string): void {
    const records = this.metrics.get(pluginId);
    if (!records) return;

    const cutoff = Date.now() - (this.aggregationInterval * 60); // Keep 1 hour
    const filtered = records.filter(r => r.timestamp >= cutoff);
    this.metrics.set(pluginId, filtered);
  }

  getAllMetrics(): Map<string, PluginMetrics> {
    const result = new Map<string, PluginMetrics>();
    for (const pluginId of this.metrics.keys()) {
      result.set(pluginId, this.getMetrics(pluginId));
    }
    return result;
  }
}

