export interface OutputFormatter {
  format(data: unknown, options?: FormatOptions): string;
  formatError(error: Error): string;
}

export interface FormatOptions {
  style?: 'json' | 'table' | 'tree' | 'list' | 'yaml';
  indent?: number;
  colors?: boolean;
  maxWidth?: number;
}

export class JSONOutputFormatter implements OutputFormatter {
  format(data: unknown, options: FormatOptions = {}): string {
    const indent = options.indent ?? 2;
    const json = JSON.stringify(data, null, indent);

    if (options.colors) {
      return this.highlightJSON(json);
    }

    return json;
  }

  formatError(error: Error): string {
    return JSON.stringify({
      error: error.name,
      message: error.message,
      stack: error.stack
    }, null, 2);
  }

  private highlightJSON(json: string): string {
    // Simple syntax highlighting
    return json
      .replace(/"([^"]+)":/g, '\x1b[33m"$1"\x1b[0m:')
      .replace(/:\s*"([^"]*)"/g, ': \x1b[36m"$1"\x1b[0m');
  }
}

export class TableOutputFormatter implements OutputFormatter {
  format(data: unknown, options: FormatOptions = {}): string {
    if (!Array.isArray(data)) {
      return String(data);
    }

    if (data.length === 0) return '(empty)';

    const headers = Object.keys(data[0] as object);
    const rows = data.map(item => 
      headers.map(h => String((item as Record<string, unknown>)[h] ?? ''))
    );

    return this.renderTable(headers, rows, options.maxWidth || 100);
  }

  formatError(error: Error): string {
    return `Error: ${error.message}`;
  }

  private renderTable(
    headers: string[],
    rows: string[][],
    maxWidth: number
  ): string {
    const colWidths = headers.map((h, i) => {
      const maxCellWidth = Math.max(
        h.length,
        ...rows.map(r => (r[i] || '').length)
      );
      return Math.min(maxCellWidth, Math.floor(maxWidth / headers.length));
    });

    const headerRow = headers
      .map((h, i) => h.padEnd(colWidths[i]).slice(0, colWidths[i]))
      .join(' | ');

    const separator = colWidths.map(w => '-'.repeat(w)).join('-+-');

    const dataRows = rows.map(row =>
      row.map((cell, i) => 
        String(cell).padEnd(colWidths[i]).slice(0, colWidths[i])
      ).join(' | ')
    );

    return [headerRow, separator, ...dataRows].join('\n');
  }
}

