}

export interface GCThresholds {
  maxAge?: number;
  maxSize?: number;
  maxEntries?: number;
}

export interface GCStats {
  lastRun?: Date;
  entriesRemoved: number;
  bytesFreed: number;
  duration: number;
}

export class DefaultMemoryGC implements MemoryGC {
  private thresholds: GCThresholds = {
    maxAge: 7 * 24 * 60 * 60 * 1000, // 7 days
    maxSize: 100 * 1024 * 1024, // 100MB
    maxEntries: 10000
  };

  private stats: GCStats = {
    entriesRemoved: 0,
    bytesFreed: 0,
    duration: 0
  };

  constructor(
    private storage: MemoryStorage,
    private index: MemoryIndex
  ) {}

  async run(): Promise<GCRemove> {
    const startTime = Date.now();
    let entriesRemoved = 0;
    let bytesFreed = 0;

    const allKeys = await this.storage.getAllKeys();
    const toRemove: string[] = [];

    for (const key of allKeys) {
      const entry = await this.storage.get(key);
      if (!entry) continue;

      let shouldRemove = false;

      if (this.thresholds.maxAge) {
        const age = Date.now() - entry.timestamp;
        if (age > this.thresholds.maxAge) {
          shouldRemove = true;
        }
      }

      if (this.thresholds.maxSize) {
        const totalSize = await this.calculateTotalSize();
        if (totalSize > this.thresholds.maxSize) {
          shouldRemove = true;
        }
      }

      if (this.thresholds.maxEntries && allKeys.length > this.thresholds.maxEntries) {
        shouldRemove = true;
      }

      if (shouldRemove) {
        toRemove.push(key);
        bytesFreed += this.estimateEntrySize(entry);
        entriesRemoved++;
      }
    }

    for (const key of toRemove) {
      await this.storage.delete(key);
      this.index.remove(key);
    }

    this.stats = {
      lastRun: new Date(),
      entriesRemoved,
      bytesFreed,
      duration: Date.now() - startTime
    };

    return { entriesRemoved, bytesFreed };
  }

  getStats(): GCStats {
    return { ...this.stats };
  }

  setThresholds(thresholds: GCThresholds): void {
    this.thresholds = { ...this.thresholds, ...thresholds };
  }

  private async calculateTotalSize(): Promise<number> {
    return 0;
  }

  private estimateEntrySize(entry: unknown): number {
    return new TextEncoder().encode(JSON.stringify(entry)).length;
  }
}

