export interface ToolValidator {
  validate(args: unknown, schema: JSONSchema): ValidationResult;
  validateResult(result: unknown, schema: JSONSchema): ValidationResult;
}

export interface ValidationResult {
  valid: boolean;
  errors: ValidationError[];
}

export interface ValidationError {
  path: string;
  message: string;
  value?: unknown;
}

export class JSONSchemaToolValidator implements ToolValidator {
  validate(args: unknown, schema: JSONSchema): ValidationResult {
    const errors: ValidationError[] = [];

    if (typeof args !== 'object' || args === null) {
      return {
        valid: false,
        errors: [{ path: '', message: 'Args must be an object' }]
      };
    }

    this.validateObject(args as Record<string, unknown>, schema, '', errors);

    return {
      valid: errors.length === 0,
      errors
    };
  }

  validateResult(result: unknown, schema: JSONSchema): ValidationResult {
    const errors: ValidationError[] = [];
    this.validateValue(result, schema, '', errors);
    return { valid: errors.length === 0, errors };
  }

  private validateObject(
    obj: Record<string, unknown>,
    schema: JSONSchema,
    path: string,
    errors: ValidationError[]
  ): void {
    if (schema.type !== 'object') return;

    const required = schema.required || [];
    for (const field of required) {
      if (!(field in obj)) {
        errors.push({ path: `${path}.${field}`, message: `Required field missing` });
      }
    }

    const properties = schema.properties || {};
    for (const [key, value] of Object.entries(obj)) {
      const fieldSchema = properties[key];
      if (!fieldSchema) {
        if (schema.additionalProperties === false) {
          errors.push({ path: `${path}.${key}`, message: 'Unknown field' });
        }
        continue;
      }
      this.validateValue(value, fieldSchema, `${path}.${key}`, errors);
    }
  }

  private validateValue(
    value: unknown,
    schema: JSONSchema,
    path: string,
    errors: ValidationError[]
  ): void {
    if (schema.type) {
      if (!this.checkType(value, schema.type)) {
        errors.push({ path, message: `Expected ${schema.type}` });
        return;
      }
    }

    if (schema.enum && !schema.enum.includes(value)) {
      errors.push({ path, message: `Value must be one of: ${schema.enum.join(', ')}` });
    }

    if (schema.type === 'string' && typeof value === 'string') {
      if (schema.minLength !== undefined && value.length < schema.minLength) {
        errors.push({ path, message: `String too short` });
      }
      if (schema.maxLength !== undefined && value.length > schema.maxLength) {
        errors.push({ path, message: `String too long` });
      }
      if (schema.pattern) {
        const regex = new RegExp(schema.pattern);
        if (!regex.test(value)) {
          errors.push({ path, message: `String does not match pattern` });
        }
      }
    }

    if (schema.type === 'number' && typeof value === 'number') {
      if (schema.minimum !== undefined && value < schema.minimum) {
        errors.push({ path, message: `Number below minimum` });
      }
      if (schema.maximum !== undefined && value > schema.maximum) {
        errors.push({ path, message: `Number above maximum` });
      }
    }

    if (schema.type === 'array' && Array.isArray(value)) {
      if (schema.items) {
        value.forEach((item, index) => {
          this.validateValue(item, schema.items!, `${path}[${index}]`, errors);
        });
      }
    }

    if (schema.type === 'object') {
      this.validateObject(value as Record<string, unknown>, schema, path, errors);
    }
  }

  private checkType(value: unknown, type: string): boolean {
    switch (type) {
      case 'string': return typeof value === 'string';
      case 'number': return typeof value === 'number';
      case 'boolean': return typeof value === 'boolean';
      case 'array': return Array.isArray(value);
      case 'object': return typeof value === 'object' && value !== null && !Array.isArray(value);
      case 'null': return value === null;
      default: return true;
    }
  }
}

