export class DefaultSkillDependencyGraph implements SkillDependencyGraph {
  private adjacency = new Map<string, Set<string>>();
  private reverseAdjacency = new Map<string, Set<string>>();

  addSkill(skill: Skill): void {
    if (!this.adjacency.has(skill.id)) {
      this.adjacency.set(skill.id, new Set());
    }
    if (!this.reverseAdjacency.has(skill.id)) {
      this.reverseAdjacency.set(skill.id, new Set());
    }

    for (const dep of skill.dependencies || []) {
      this.adjacency.get(skill.id)!.add(dep);
      if (!this.reverseAdjacency.has(dep)) {
        this.reverseAdjacency.set(dep, new Set());
      }
      this.reverseAdjacency.get(dep)!.add(skill.id);
    }
  }

  removeSkill(skillId: string): void {
    const deps = this.adjacency.get(skillId);
    if (deps) {
      for (const dep of deps) {
        this.reverseAdjacency.get(dep)?.delete(skillId);
      }
    }

    const dependents = this.reverseAdjacency.get(skillId);
    if (dependents) {
      for (const dependent of dependents) {
        this.adjacency.get(dependent)?.delete(skillId);
      }
    }

    this.adjacency.delete(skillId);
    this.reverseAdjacency.delete(skillId);
  }

  getDependencies(skillId: string): string[] {
    return Array.from(this.adjacency.get(skillId) || []);
  }

  getDependents(skillId: string): string[] {
    return Array.from(this.reverseAdjacency.get(skillId) || []);
  }

  topologicalSort(): string[] {
    const visited = new Set<string>();
    const result: string[] = [];
    const temp = new Set<string>();

    const visit = (node: string) => {
      if (temp.has(node)) {
        throw new CycleError(`Cycle detected involving ${node}`);
      }
      if (visited.has(node)) return;

      temp.add(node);

      for (const dep of this.adjacency.get(node) || []) {
        visit(dep);
      }

      temp.delete(node);
      visited.add(node);
      result.push(node);
    };

    for (const node of this.adjacency.keys()) {
      if (!visited.has(node)) {
        visit(node);
      }
    }

    return result;
  }

  detectCycles(): Cycle[] {
    const cycles: Cycle[] = [];
    const visited = new Set<string>();
    const stack: string[] = [];

    const dfs = (node: string): void => {
      if (stack.includes(node)) {
        const cycleStart = stack.indexOf(node);
        const cycleNodes = stack.slice(cycleStart);
        const edges: [string, string][] = [];
        for (let i = 0; i < cycleNodes.length; i++) {
          edges.push([cycleNodes[i], cycleNodes[(i + 1) % cycleNodes.length]]);
        }
        cycles.push({ nodes: cycleNodes, edges });
        return;
      }

      if (visited.has(node)) return;

      stack.push(node);
      visited.add(node);

      for (const dep of this.adjacency.get(node) || []) {
        dfs(dep);
      }

      stack.pop();
    };

    for (const node of this.adjacency.keys()) {
      dfs(node);
    }

    return cycles;
  }
}

