export interface CLICompletable {
  getCompletions(
    line: string,
    state: CompletionState
  ): Promise<CompletionResult[]>;
}

export interface CompletionState {
  cursor: number;
  tokens: string[];
  lastToken: string;
  context: Record<string, unknown>;
}

export interface CompletionResult {
  completion: string;
  type: CompletionType;
  description?: string;
  icon?: string;
}

export type CompletionType = 
  | 'command'
  | 'subcommand'
  | 'option'
  | 'option-value'
  | 'argument'
  | 'file'
  | 'directory'
  | 'skill'
  | 'tool'
  | 'variable';

export class ShellCompleter implements CLICompletable {
  private commands: Map<string, CommandSpec> = new Map();

  constructor(
    private fileCompleter: FileCompleter,
    private skillCompleter: SkillCompleter
  ) {}

  registerCommand(name: string, spec: CommandSpec): void {
    this.commands.set(name, spec);
  }

  async getCompletions(
    line: string,
    state: CompletionState
  ): Promise<CompletionResult[]> {
    const { tokens, lastToken } = state;

    if (tokens.length === 0) {
      return this.completeCommand(lastToken);
    }

    const firstToken = tokens[0];
    const command = this.commands.get(firstToken);

    if (!command) {
      return this.completeCommand(lastToken);
    }

    if (tokens.length === 1) {
      return this.completeSubcommand(command, lastToken);
    }

    if (tokens.length === 2 && (lastToken.startsWith('-') || tokens[1] === 'help')) {
      return this.completeOption(command, lastToken);
    }

    return this.completeArgument(command, tokens, lastToken, state.context);
  }

  private async completeCommand(partial: string): Promise<CompletionResult[]> {
    const matches = Array.from(this.commands.keys())
      .filter(cmd => cmd.startsWith(partial));

    return matches.map(cmd => ({
      completion: cmd,
      type: 'command' as CompletionType,
      description: this.commands.get(cmd)?.description
    }));
  }

  private async completeSubcommand(
    command: CommandSpec,
    partial: string
  ): Promise<CompletionResult[]> {
    const subs = command.subcommands || [];
    return subs
      .filter(sub => sub.name.startsWith(partial))
      .map(sub => ({
        completion: sub.name,
        type: 'subcommand' as CompletionType,
        description: sub.description
      }));
  }

  private async completeOption(
    command: CommandSpec,
    partial: string
  ): Promise<CompletionResult[]> {
    const options = command.options || [];
    return options
      .filter(opt => opt.name.startsWith(partial) || opt.short?.startsWith(partial))
      .map(opt => ({
        completion: `--${opt.name}`,
        type: 'option' as CompletionType,
        description: opt.description
      }));
  }

  private async completeArgument(
    command: CommandSpec,
    tokens: string[],
    lastToken: string,
    context: Record<string, unknown>
  ): Promise<CompletionResult[]> {
    const argSpec = this.getArgumentSpec(command, tokens.length - 1);

    if (!argSpec) return [];

    switch (argSpec.type) {
      case 'file':
        return this.fileCompleter.complete(lastToken, argSpec.filter);
      case 'skill':
        return this.skillCompleter.complete(lastToken);
      default:
        return [];
    }
  }

  private getArgumentSpec(command: CommandSpec, position: number): ArgumentSpec | null {
    const args = command.arguments || [];
    return args[position] || null;
  }
}

