export interface EntityMemory {
  create(entity: Entity): Promise<void>;
  get(entityId: string): Promise<Entity | null>;
  update(entityId: string, updates: Partial<Entity>): Promise<void>;
  delete(entityId: string): Promise<void>;
  findByType(type: string): Promise<Entity[]>;
  search(query: string): Promise<Entity[]>;
}

export interface Entity {
  id: string;
  type: string;
  name: string;
  observations: string[];
  metadata: Record<string, unknown>;
  createdAt: Date;
  updatedAt: Date;
}

export class KnowledgeGraphMemory implements EntityMemory {
  private entities = new Map<string, Entity>();
  private relations: Relation[] = [];
  private typeIndex = new Map<string, Set<string>>();
  private searchIndex: InMemoryIndex;

  constructor() {
    this.searchIndex = new InMemoryIndex();
  }

  async create(entity: Entity): Promise<void> {
    entity.createdAt = new Date();
    entity.updatedAt = new Date();

    this.entities.set(entity.id, entity);

    if (!this.typeIndex.has(entity.type)) {
      this.typeIndex.set(entity.type, new Set());
    }
    this.typeIndex.get(entity.type)!.add(entity.id);

    this.indexEntity(entity);
  }

  async get(entityId: string): Promise<Entity | null> {
    return this.entities.get(entityId) || null;
  }

  async update(entityId: string, updates: Partial<Entity>): Promise<void> {
    const entity = this.entities.get(entityId);
    if (!entity) {
      throw new EntityNotFoundError(entityId);
    }

    const updated = { ...entity, ...updates, updatedAt: new Date() };
    this.entities.set(entityId, updated);
    this.indexEntity(updated);
  }

  async delete(entityId: string): Promise<void> {
    const entity = this.entities.get(entityId);
    if (entity) {
      this.typeIndex.get(entity.type)?.delete(entityId);
      this.entities.delete(entityId);
      this.searchIndex.remove(entityId);
      this.relations = this.relations.filter(
        r => r.from !== entityId && r.to !== entityId
      );
    }
  }

  async findByType(type: string): Promise<Entity[]> {
    const ids = this.typeIndex.get(type) || new Set();
    return Array.from(ids)
      .map(id => this.entities.get(id))
      .filter((e): e is Entity => e !== undefined);
  }

  async search(query: string): Promise<Entity[]> {
    const ids = this.searchIndex.search(query, 20);
    return ids
      .map(id => this.entities.get(id))
      .filter((e): e is Entity => e !== undefined);
  }

  async addRelation(from: string, to: string, type: string): Promise<void> {
    this.relations.push({ from, to, type, createdAt: new Date() });
  }

  async getRelations(entityId: string): Promise<Relation[]> {
    return this.relations.filter(
      r => r.from === entityId || r.to === entityId
    );
  }

  private indexEntity(entity: Entity): void {
    const text = `${entity.name} ${entity.observations.join(' ')}`;
    this.searchIndex.add(entity.id, { text, type: entity.type });
  }
}

