export class ComprehensiveSkillHealthCheck implements SkillHealthCheck {
  constructor(
    private toolRegistry: ToolRegistry,
    private dependencyGraph: SkillDependencyGraph
  ) {}

  async check(skill: Skill): Promise<HealthCheckResult> {
    const checks: CheckResult[] = [];

    checks.push(this.checkSchema(skill));
    checks.push(this.checkDependencies(skill));
    checks.push(this.checkActions(skill));
    checks.push(await this.checkTools(skill));

    return {
      skillId: skill.id,
      healthy: checks.every(c => c.passed),
      checks,
      timestamp: new Date()
    };
  }

  private checkSchema(skill: Skill): CheckResult {
    const start = Date.now();

    try {
      if (!skill.name) {
        return { name: 'schema', passed: false, message: 'Missing name', duration: Date.now() - start };
      }
      if (!skill.id) {
        return { name: 'schema', passed: false, message: 'Missing id', duration: Date.now() - start };
      }
      return { name: 'schema', passed: true, duration: Date.now() - start };
    } catch (error) {
      return { name: 'schema', passed: false, message: error.message, duration: Date.now() - start };
    }
  }

  private checkDependencies(skill: Skill): CheckResult {
    const start = Date.now();

    try {
      const deps = this.dependencyGraph.getDependencies(skill.id);
      const cycles = this.dependencyGraph.detectCycles();

      if (cycles.length > 0) {
        return { 
          name: 'dependencies', 
          passed: false, 
          message: `Cycle detected: ${cycles[0].nodes.join(' -> ')}`,
          duration: Date.now() - start 
        };
      }

      return { name: 'dependencies', passed: true, duration: Date.now() - start };
    } catch (error) {
      return { name: 'dependencies', passed: false, message: error.message, duration: Date.now() - start };
    }
  }

  private checkActions(skill: Skill): CheckResult {
    const start = Date.now();

    if (!skill.actions || skill.actions.length === 0) {
      return { 
        name: 'actions', 
        passed: false, 
        message: 'No actions defined',
        duration: Date.now() - start 
      };
    }

    for (const action of skill.actions) {
      if (!action.name) {
        return { 
          name: 'actions', 
          passed: false, 
          message: 'Action missing name',
          duration: Date.now() - start 
        };
      }
    }

    return { name: 'actions', passed: true, duration: Date.now() - start };
  }

  private async checkTools(skill: Skill): Promise<CheckResult> {
    const start = Date.now();

    const requiredTools = this.extractRequiredTools(skill);
    const availableTools = await this.toolRegistry.listTools();
    const availableNames = new Set(availableTools.map(t => t.name));

    const missing = requiredTools.filter(t => !availableNames.has(t));

    if (missing.length > 0) {
      return { 
        name: 'tools', 
        passed: false, 
        message: `Missing tools: ${missing.join(', ')}`,
        duration: Date.now() - start 
      };
    }

    return { name: 'tools', passed: true, duration: Date.now() - start };
  }

  private extractRequiredTools(skill: Skill): string[] {
    const tools: string[] = [];
    // Extract tool references from skill actions
