export interface PluginLoader {
  load(pluginPath: string): Promise<LoadedPlugin>;
  unload(pluginId: string): Promise<void>;
  reload(pluginId: string): Promise<LoadedPlugin>;
}

export interface LoadedPlugin {
  plugin: Plugin;
  instance: PluginInstance;
  loadedAt: Date;
}

export class DefaultPluginLoader implements PluginLoader {
  private loadedPlugins = new Map<string, LoadedPlugin>();
  private moduleCache = new Map<string, NodeModule>();

  constructor(
    private resolver: PluginResolver,
    private validator: PluginValidator,
    private sandbox: PluginSandbox
  ) {}

  async load(pluginPath: string): Promise<LoadedPlugin> {
    const pluginId = this.resolver.resolveId(pluginPath);

    if (this.loadedPlugins.has(pluginId)) {
      return this.loadedPlugins.get(pluginId)!;
    }

    const manifest = await this.loadManifest(pluginPath);
    this.validator.validate(manifest);

    const module = await this.loadModule(pluginPath);
    const instance = await this.createInstance(module, manifest);

    if (instance.init) {
      await instance.init(this.createContext(pluginId));
    }

    const loaded: LoadedPlugin = {
      plugin: manifest,
      instance,
      loadedAt: new Date()
    };

    this.loadedPlugins.set(pluginId, loaded);
    this.moduleCache.set(pluginId, module);

    return loaded;
  }

  async unload(pluginId: string): Promise<void> {
    const loaded = this.loadedPlugins.get(pluginId);
    if (!loaded) {
      return;
    }

    if (loaded.instance.destroy) {
      await loaded.instance.destroy();
    }

    this.loadedPlugins.delete(pluginId);
    this.moduleCache.delete(pluginId);
  }

  async reload(pluginId: string): Promise<LoadedPlugin> {
    await this.unload(pluginId);
    const loaded = this.loadedPlugins.get(pluginId);
    if (!loaded) {
      throw new PluginNotLoadedError(pluginId);
    }
    return this.load(loaded.plugin.location);
  }

  private async loadManifest(path: string): Promise<Plugin> {
    const manifestPath = join(path, 'plugin.json');
    const content = await fs.readFile(manifestPath, 'utf-8');
    return JSON.parse(content);
  }

  private async loadModule(path: string): Promise<NodeModule> {
    // Load plugin module with sandbox
    const entryPoint = join(path, 'index.js');
    return require(entryPoint);
  }

  private async createInstance(
    module: NodeModule,
    manifest: Plugin
  ): Promise<PluginInstance> {
    if (typeof module.default === 'function') {
      return module.default();
    }
    return module;
  }

  private createContext(pluginId: string): PluginContext {
    return new PluginContext(pluginId, this.sandbox);
  }
}

