export interface PipeChain {
  pipe(command: string): this;
  pipe(command: string, args: unknown[]): this;
  run(): Promise<PipeResult>;
}

export interface PipeResult {
  success: boolean;
  outputs: unknown[];
  errors: Error[];
  duration: number;
}

export class CommandPipeChain implements PipeChain {
  private commands: PipeCommand[] = [];
  private context: PipeContext;

  constructor(
    private executor: CommandExecutor,
    context?: PipeContext
  ) {
    this.context = context || {};
  }

  pipe(command: string, args: unknown[] = []): this {
    this.commands.push({ command, args });
    return this;
  }

  async run(): Promise<PipeResult> {
    const startTime = Date.now();
    const outputs: unknown[] = [];
    const errors: Error[] = [];
    let previousOutput: unknown;

    for (let i = 0; i < this.commands.length; i++) {
      const { command, args } = this.commands[i];

      try {
        const input = i === 0 ? undefined : previousOutput;
        const result = await this.executor.execute(command, args, {
          ...this.context,
          pipeInput: input
        });

        outputs.push(result);
        previousOutput = result;
      } catch (error) {
        errors.push(error as Error);
        if (this.context.stopOnError) {
          break;
        }
      }
    }

    return {
      success: errors.length === 0,
      outputs,
      errors,
      duration: Date.now() - startTime
    };
  }

  static from(cli: CommandExecutor): PipeChain {
    return new CommandPipeChain(cli);
  }
}

