export interface MemoryCompressor {
  compress(memory: MemoryBlock): CompressedBlock;
  decompress(block: CompressedBlock): MemoryBlock;
}

export interface MemoryBlock {
  id: string;
  data: unknown;
  metadata: Record<string, unknown>;
}

export interface CompressedBlock {
  id: string;
  compressed: Buffer;
  algorithm: string;
  originalSize: number;
  compressedSize: number;
}

export class ZlibMemoryCompressor implements MemoryCompressor {
  compress(memory: MemoryBlock): CompressedBlock {
    const json = JSON.stringify(memory);
    const originalSize = Buffer.byteLength(json, 'utf-8');
    const compressed = zlib.deflateSync(Buffer.from(json));

    return {
      id: memory.id,
      compressed,
      algorithm: 'zlib',
      originalSize,
      compressedSize: compressed.length
    };
  }

  decompress(block: CompressedBlock): MemoryBlock {
    const decompressed = zlib.inflateSync(block.compressed).toString();
    return JSON.parse(decompressed);
  }
}

export class LZ4MemoryCompressor implements MemoryCompressor {
  compress(memory: MemoryBlock): CompressedBlock {
    const json = JSON.stringify(memory);
    const originalSize = Buffer.byteLength(json, 'utf-8');
    const compressed = LZ4.encode(Buffer.from(json));

    return {
      id: memory.id,
      compressed,
      algorithm: 'lz4',
      originalSize,
      compressedSize: compressed.length
    };
  }

  decompress(block: CompressedBlock): MemoryBlock {
    const decompressed = LZ4.decode(block.compressed);
    return JSON.parse(decompressed.toString());
  }
}

export class TieredMemoryStorage {
  private hot = new Map<string, MemoryBlock>();n  private warm = new LRUCache<string, CompressedBlock>(1000);
  private cold: ColdStorage;

  constructor(coldStorage: ColdStorage) {
    this.cold = coldStorage;
  }

  async get(id: string): Promise<MemoryBlock | null> {
    // Check hot first
    if (this.hot.has(id)) {
      return this.hot.get(id)!;
    }

    // Check warm
    const warmBlock = await this.warm.get(id);
    if (warmBlock) {
      const compressor = this.getCompressor(warmBlock.algorithm);
      const block = compressor.decompress(warmBlock);
      this.hot.set(id, block);
      return block;
    }

    // Check cold
    const coldBlock = await this.cold.get(id);
    if (coldBlock) {
      const compressor = this.getCompressor(coldBlock.algorithm);
      const block = compressor.decompress(coldBlock);
      this.hot.set(id, block);
      await this.warm.set(id, coldBlock);
      return block;
    }

    return null;
  }

  async set(id: string, block: MemoryBlock): Promise<void> {
    this.hot.set(id, block);

    if (this.hot.size > 1000) {
      const evicted = this.hotEntries()[0];
      const warmBlock = this.compress(evicted);
      await this.warm.set(evicted.id, warmBlock);
      this.hot.delete(evicted.id);
    }
  }

  private getCompressor(algorithm: string): MemoryCompressor {
    switch (algorithm) {
      case 'lz4': return new LZ4MemoryCompressor();
      default: return new ZlibMemoryCompressor();
    }
  }

  private hotEntries(): MemoryBlock[] {
    return Array.from(this.hot.values());
  }
}

