        `${target.url}/deployments`,
        {
          deploymentId,
          skillId: skill.id,
          artifacts: uploadResult.urls,
          config: skill.config
        }
      );

      return {
        deploymentId,
        success: true,
        endpoint: `${target.url}/skills/${skill.id}`
      };
