export class StarterPluginTemplate implements PluginTemplate {
  id = 'starter';
  name = 'Starter Plugin';
  description = 'Basic plugin template with common patterns';

  async generate(options: TemplateOptions): Promise<GeneratedPlugin> {
    const { name } = options;
    const safeName = this.toSafeName(name);
    const files: GeneratedFile[] = [];

    files.push({
      path: `${safeName}/package.json`,
      content: this.renderPackageJson(options)
    });

    files.push({
      path: `${safeName}/plugin.json`,
      content: this.renderPluginManifest(options)
    });

    files.push({
      path: `${safeName}/src/index.ts`,
      content: this.renderIndex(options)
    });

    files.push({
      path: `${safeName}/src/tools/my-tool.ts`,
      content: this.renderTool(options)
    });

    files.push({
      path: `${safeName}/tsconfig.json`,
      content: this.renderTsConfig()
    });

    return {
      path: safeName,
      files
    };
  }

  private toSafeName(name: string): string {
    return name.toLowerCase().replace(/[^a-z0-9]+/g, '-');
  }

  private renderPackageJson(options: TemplateOptions): string {
    return JSON.stringify({
      name: options.name,
      version: '0.1.0',
      description: options.description || '',
      main: 'dist/index.js',
      scripts: {
        build: 'tsc',
        test: 'jest'
      },
      dependencies: {
        '@openclaw/sdk': '^2.0.0'
      },
      devDependencies: {
        typescript: '^5.0.0',
        '@types/node': '^20.0.0'
      }
    }, null, 2);
  }

  private renderPluginManifest(options: TemplateOptions): string {
    return JSON.stringify({
      id: this.toSafeName(options.name),
      name: options.name,
      version: '0.1.0',
      author: options.author || '',
      description: options.description || '',
      tools: ['my-tool']
    }, null, 2);
  }

  private renderIndex(options: TemplateOptions): string {
    return `import { Plugin } from '@openclaw/sdk';

const plugin: Plugin = {
  id: '${this.toSafeName(options.name)}',
  name: '${options.name}',
  version: '0.1.0',
  tools: [],
  init: async (context) => {
    console.log('Plugin initialized');
  }
};

export default plugin;`;
  }

  private renderTool(options: TemplateOptions): string {
    return `import { Tool } from '@openclaw/sdk';

export const myTool: Tool = {
  name: 'my-tool',
  description: 'My custom tool',
  inputSchema: {
    type: 'object',
    properties: {},
    required: []
  },
  handler: async (args, context) => {
    return { result: 'Hello from my tool' };
  }
};`;
  }

  private renderTsConfig(): string {
    return JSON.stringify({
      compilerOptions: {
        target: 'ES2020',
        module: 'commonjs',
        outDir: './dist',
        rootDir: './src',
        strict: true,
        esModuleInterop: true
      },
      include: ['src/**/*'],
      exclude: ['node_modules']
    }, null, 2);
  }
}

