export interface StreamHandler {
  handleStream(
    stream: ReadableStream,
    options: StreamOptions
  ): AsyncIterable<string>;
}

export interface StreamOptions {
  encoding?: BufferEncoding;
  delimiter?: string;
  onError?: (error: Error) => void;
}

export class LineDelimitedStreamHandler implements StreamHandler {
  async handleStream(
    stream: ReadableStream,
    options: StreamOptions = {}
  ): AsyncIterable<string> {
    const delimiter = options.delimiter || '\n';
    let buffer = '';

    const reader = stream.getReader();
    const decoder = new TextDecoder(options.encoding || 'utf-8');

    return {
      async *[Symbol.asyncIterator]() {
        while (true) {
          const { done, value } = await reader.read();

          if (done) {
            if (buffer.length > 0) {
              yield buffer;
            }
            break;
          }

          buffer += decoder.decode(value, { stream: true });
          const parts = buffer.split(delimiter);

          buffer = parts.pop() || '';

          for (const part of parts) {
            yield part;
          }
        }
      }
    };
  }
}

export class JSONStreamHandler implements StreamHandler {
  async handleStream(
    stream: ReadableStream,
    options: StreamOptions = {}
  ): AsyncIterable<unknown> {
    let buffer = '';

    const reader = stream.getReader();
    const decoder = new TextDecoder(options.encoding || 'utf-8');

    return {
      async *[Symbol.asyncIterator]() {
        while (true) {
          const { done, value } = await reader.read();

          if (done) {
            break;
          }

          buffer += decoder.decode(value, { stream: true });

          try {
            yield JSON.parse(buffer);
            buffer = '';
          } catch {
            // Not complete JSON yet
          }
        }
      }
    };
  }
}

export class CommandOutputStreamer {
  constructor(
    private streamHandler: StreamHandler
  ) {}

  async streamCommand(
    command: string,
    args: string[]
  ): Promise<string[]> {
    const output: string[] = [];
    const stream = spawn(command, args);

    for await (const line of this.streamHandler.handleStream(stream.stdout)) {
      output.push(line);
    }

    return output;
  }
}

